import { Box, Flex, Text } from '@chakra-ui/react';
import { Trans, useTranslation } from 'react-i18next';
import { AccountDocument, DocumentType } from '@domain/accountDocument';
import { FileUpload } from '@state/utils';
import { UploadIcon } from '@ui/assets/icons/UploadIcon';
import { FormControl } from '@ui/components/formControls/FormControl';
import { useControl } from '@ui/components/formControls/hooks';
import { FileUploader } from '@ui/components/molecules/FileUploader';
import { Upload } from '@ui/components/molecules/FileUploader/types';
import { Label, Meta } from '@ui/components/typography';
import { useDocumentationUploader } from './useDocumentationUploader';

type Props = {
  currentFile?: AccountDocument;
  description: string;
  documentType: DocumentType;
  isRequired?: boolean;
  label: string;
};

export const DocumentationUploader = ({
  currentFile,
  description,
  documentType,
  isRequired,
  label,
}: Props) => {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'documentation.uploader' });
  const { error } = useControl({ name: documentType });
  const initialUploads: FileUpload[] = currentFile
    ? [
        {
          file: new File([], currentFile.file.name),
          id: currentFile.id,
          progressPercentage: 100,
          status: 'complete',
        },
      ]
    : [];

  const { addFile, removeFile, uploads } = useDocumentationUploader({
    documentType,
    initialUploads,
  });

  const onAddFiles = (files: File[]) => {
    files.forEach((file) => addFile(file));
  };

  const uploadArr: Upload[] = uploads.map((upload) => ({
    file: upload.file,
    progress: upload.progressPercentage,
    status: upload.status,
  }));

  return (
    <FormControl formLabelProps={{ variant: 'bold' }} isRequired={isRequired} label={label}>
      <Flex direction="column" gap={2}>
        <Meta>{description}</Meta>
        <FileUploader
          acceptedFileTypes={['application/pdf', 'image/jpeg', 'image/png']}
          hasError={!!error}
          onAddFiles={onAddFiles}
          onRemoveFile={removeFile}
          previewPath={currentFile?.file.url}
          uploads={uploadArr}
          useAbsolutePreviewPath
        >
          <Flex alignItems="center" direction="column" gap={2} p={3}>
            <UploadIcon color="neutral.600" height="24px" width="24px" />
            <Label variant="bold">
              <Trans
                components={[<Text as="span" color="blue.600" key="label-text" />]}
                i18nKey="label"
                t={t}
              />
            </Label>
            <Box fontSize={13}>{t('description')}</Box>
          </Flex>
        </FileUploader>
      </Flex>
    </FormControl>
  );
};
